/* ===== SMALL COMPONENTS ===== */
const BG = "#030712";
const FONT = "'Inter',system-ui,-apple-system,sans-serif";

function AN({ target }) {
  const [v, setV] = useState(0);
  useEffect(() => { let s = 0; const step = target / 75; const t = setInterval(() => { s += step; if (s >= target) { setV(target); clearInterval(t); } else setV(Math.round(s)); }, 16); return () => clearInterval(t); }, [target]);
  return <>{v}</>;
}

function Ring({ score, size, thick, zone, glow = true }) {
  if (score === null) return <div style={{ width: size, height: size, borderRadius: "50%", border: "2px dashed rgba(255,255,255,0.1)", display: "flex", alignItems: "center", justifyContent: "center" }}><span style={{ fontSize: size * .15, color: "#475569" }}>TBD</span></div>;
  const c = ZC[zone], r = (size - thick) / 2, ci = 2 * Math.PI * r, pr = (score / 100) * ci, id = "r" + Math.random().toString(36).slice(2, 8);
  return (
    <div style={{ position: "relative", width: size, height: size, flexShrink: 0 }}>
      <svg width={size} height={size} style={{ transform: "rotate(-90deg)", display: "block" }}>
        <defs>
          <linearGradient id={id} x1="0%" y1="0%" x2="100%" y2="100%"><stop offset="0%" stopColor={c.m} /><stop offset="100%" stopColor={c.m} stopOpacity={.3} /></linearGradient>
          {glow && <filter id={"g" + id}><feGaussianBlur stdDeviation="3" result="b" /><feMerge><feMergeNode in="b" /><feMergeNode in="SourceGraphic" /></feMerge></filter>}
        </defs>
        <circle cx={size / 2} cy={size / 2} r={r} fill="none" stroke="rgba(255,255,255,0.04)" strokeWidth={thick} />
        <circle cx={size / 2} cy={size / 2} r={r} fill="none" stroke={"url(#" + id + ")"} strokeWidth={thick} strokeLinecap="round" strokeDasharray={pr + " " + ci} style={{ transition: "stroke-dasharray 1.5s cubic-bezier(0.4,0,0.2,1)" }} filter={glow ? "url(#g" + id + ")" : undefined} />
      </svg>
      <div style={{ position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center" }}>
        <div style={{ fontSize: size * .28, fontWeight: 900, color: "white", lineHeight: 1 }}><AN target={score} /></div>
      </div>
    </div>
  );
}

function Tr({ trend }) {
  if (trend == null) return null;
  const u = trend > 0, f = trend === 0;
  return <span style={{ fontSize: 9, fontWeight: 700, padding: "2px 6px", borderRadius: 6, background: f ? "rgba(255,255,255,0.05)" : u ? "rgba(16,185,129,0.15)" : "rgba(239,68,68,0.15)", color: f ? "#64748B" : u ? "#34D399" : "#F87171" }}>{f ? "\u2014" : u ? ("\u25B2+" + trend) : ("\u25BC" + trend)}</span>;
}

const LOGO="data:image/png;base64,";

function Logo({ sz }) {
  return (
    <div style={{ width: sz, height: sz, flexShrink: 0, borderRadius: sz > 24 ? 12 : 6, overflow: "hidden", background: "rgba(15,23,42,0.8)", border: "1px solid rgba(56,189,248,0.2)", boxShadow: "0 0 " + (sz * 0.4) + "px rgba(56,189,248,0.12)", display: "flex", alignItems: "center", justifyContent: "center" }}>
      <img src={LOGO} alt="CardioQ.ai" style={{ width: sz * 0.85, height: sz * 0.85, objectFit: "contain", filter: "brightness(1.3) contrast(1.1)" }} />
    </div>
  );
}

function DeepDive({ item, onClose }) {
  if (!item) return null;
  const c = ZC[item.zone];
  return (
    <div style={{ position: "fixed", inset: 0, zIndex: 200, display: "flex", justifyContent: "flex-end" }}>
      <div onClick={onClose} style={{ position: "absolute", inset: 0, background: "rgba(0,0,0,0.6)", backdropFilter: "blur(4px)" }} />
      <div style={{ position: "relative", width: "92%", maxWidth: 400, height: "100%", background: "#0B1222", overflowY: "auto", WebkitOverflowScrolling: "touch", borderLeft: "2px solid " + c.m + "22" }}>
        <button onClick={onClose} style={{ position: "sticky", top: 12, float: "right", marginRight: 12, zIndex: 10, width: 44, height: 44, borderRadius: 12, border: "1px solid rgba(255,255,255,0.1)", background: "rgba(255,255,255,0.05)", color: "white", fontSize: 18, display: "flex", alignItems: "center", justifyContent: "center" }}>{"\u2715"}</button>
        <div style={{ padding: 20, paddingBottom: 40, clear: "both" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 14, marginBottom: 20 }}>
            <Ring score={item.score} size={64} thick={5} zone={item.zone} glow={false} />
            <div><div style={{ fontSize: 20, fontWeight: 800, color: "white" }}>{item.name}</div><div style={{ fontSize: 15, color: c.m, fontWeight: 600 }}>{item.val} {item.unit}</div></div>
          </div>
          {[{ t: "WHY THIS SCORE", c: item.why, cl: "#60A5FA", bg: "rgba(59,130,246,0.06)", bd: "rgba(59,130,246,0.15)" },
            { t: "ALGORITHM LOGIC", c: item.logic, cl: "#A78BFA", bg: "rgba(139,92,246,0.06)", bd: "rgba(139,92,246,0.15)" },
            { t: "INTL BENCHMARKS", c: item.bench, cl: "#34D399", bg: "rgba(52,211,153,0.06)", bd: "rgba(52,211,153,0.15)" },
            { t: "RECOMMENDED ACTION", c: item.action, cl: "#FBBF24", bg: "rgba(251,191,36,0.08)", bd: "rgba(251,191,36,0.15)" },
          ].map((s, i) => (
            <div key={i} style={{ marginBottom: 16 }}>
              <div style={{ fontSize: 10, fontWeight: 700, color: s.cl, letterSpacing: 1.5, marginBottom: 6 }}>{s.t}</div>
              <div style={{ fontSize: 13, color: "#CBD5E1", lineHeight: 1.8, padding: 16, borderRadius: 12, background: s.bg, border: "1px solid " + s.bd }}>{s.c}</div>
            </div>
          ))}
          <div style={{ display: "flex", flexWrap: "wrap", gap: 4, marginTop: 14 }}>
            {["NHLBI", "AHA/ACC", "ESC SCORE2", "PREVENT 2023", "WHO", "IHA"].map((s, i) => <span key={i} style={{ padding: "2px 7px", borderRadius: 4, background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.06)", fontSize: 8, color: "#475569" }}>{s}</span>)}
          </div>
        </div>
      </div>
    </div>
  );
}

